// Summary: Verifies MediaPlayer layout, audio time syncing, seek commits, MediaControl integration, and volume slider behavior.

import '@testing-library/jest-dom';
import * as React from 'react';
import { render, screen, fireEvent, waitFor, act } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { MediaPlayer, type MediaPlayerProps } from './MediaPlayer';

type MockSliderProps = {
  value: number;
  onChange: (v: number) => void;
  onCommit?: (v: number) => void;
  ariaLabel?: string;
};

/**
 * NOTE: MediaPlayer tests only verify integration with Slider:
 * - Seek: onChange/onCommit update audio.currentTime and visible time label
 * - Volume: onChange maps to audio.volume
 * We do NOT test Slider behavior/semantics/aria here; those belong to Slider tests.
 */
jest.mock('../Slider', () => ({
  Slider: ({ value, onChange, onCommit, ariaLabel }: MockSliderProps) => (
    <input
      type="range"
      role="slider"
      aria-label={ariaLabel}
      data-testid={`${ariaLabel}-slider`}
      value={value}
      onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
        onChange(Number(event.target.value))
      }
      onMouseUp={(event: React.MouseEvent<HTMLInputElement>) =>
        onCommit?.(Number((event.target as HTMLInputElement).value))
      }
    />
  )
}));

const playMock = jest.fn().mockResolvedValue(undefined);
const pauseMock = jest.fn();

beforeAll(() => {
  Object.defineProperty(window.HTMLMediaElement.prototype, 'play', {
    configurable: true,
    value: playMock
  });
  Object.defineProperty(window.HTMLMediaElement.prototype, 'pause', {
    configurable: true,
    value: pauseMock
  });
});

afterEach(() => {
  jest.clearAllMocks();
});

const primeMediaElement = (
  audio: HTMLAudioElement,
  overrides?: { duration?: number; currentTime?: number; volume?: number }
) => {
  let currentTimeValue = overrides?.currentTime ?? 0;
  let durationValue = overrides?.duration ?? 0;
  let volumeValue = overrides?.volume ?? 1;

  Object.defineProperty(audio, 'currentTime', {
    configurable: true,
    get: () => currentTimeValue,
    set: value => {
      currentTimeValue = value;
    }
  });

  Object.defineProperty(audio, 'duration', {
    configurable: true,
    get: () => durationValue,
    set: value => {
      durationValue = value;
    }
  });

  Object.defineProperty(audio, 'volume', {
    configurable: true,
    get: () => volumeValue,
    set: value => {
      volumeValue = value;
    }
  });
};

const dispatchAudioEvent = (audio: HTMLAudioElement, type: string) => {
  act(() => {
    audio.dispatchEvent(new Event(type));
  });
};

const renderMediaPlayer = (props?: Partial<MediaPlayerProps>) => {
  const defaultProps: MediaPlayerProps = {
    audioSrc: '/audio/sample.mp3',
    title: 'Sample Track',
    subtitle: 'Sample Artist',
    ...props
  };

  return render(<MediaPlayer {...defaultProps} />);
};

describe('MediaPlayer', () => {
  it('renders the title', () => {
    renderMediaPlayer();
    expect(screen.getByText('Sample Track')).toBeInTheDocument();
  });

  it('renders the subtitle', () => {
    renderMediaPlayer();
    expect(screen.getByText('Sample Artist')).toBeInTheDocument();
  });

  it('default: renders two sliders (seek and volume)', () => {
    renderMediaPlayer({ variant: 'default' });
    const sliders = screen.getAllByRole('slider');
    expect(sliders.length).toBe(2);
  });


  it('updates the time display after audio metadata and timeupdate events', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 120, currentTime: 0 });
    dispatchAudioEvent(audio, 'loadedmetadata');
    audio.currentTime = 42;
    dispatchAudioEvent(audio, 'timeupdate');

    await waitFor(() => {
      expect(screen.getByText('00:42 / 02:00')).toBeInTheDocument();
    });
  });

  it('commits seek changes back to the audio element', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 180, currentTime: 0 });
    dispatchAudioEvent(audio, 'loadedmetadata');
    const seekSlider = screen.getByTestId('Seek-slider') as HTMLInputElement;

    fireEvent.change(seekSlider, { target: { value: '60' } });
    fireEvent.mouseUp(seekSlider);

    await waitFor(() => {
      expect(audio.currentTime).toBe(60);
    });
  });

  it('updates the time label after a committed seek', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 180, currentTime: 0 });
    dispatchAudioEvent(audio, 'loadedmetadata');
    const seekSlider = screen.getByTestId('Seek-slider') as HTMLInputElement;
    fireEvent.change(seekSlider, { target: { value: '60' } });
    fireEvent.mouseUp(seekSlider);
    await waitFor(() => {
      expect(screen.getByText('01:00 / 03:00')).toBeInTheDocument();
    });
  });

  it('plays on first click of the control button', async () => {
    const user = userEvent.setup();
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 90 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const controlBtn = screen.getByRole('button', { name: 'Play media' });
    await user.click(controlBtn);
    expect(playMock).toHaveBeenCalledTimes(1);
  });

  it('pauses on second click of the control button', async () => {
    const user = userEvent.setup();
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 90 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const playButton = screen.getByRole('button', { name: 'Play media' });
    await user.click(playButton);
    dispatchAudioEvent(audio, 'play');

    const pauseButton = await screen.findByRole('button', { name: 'Pause media' });
    await user.click(pauseButton);
    expect(pauseMock).toHaveBeenCalledTimes(1);
  });

  it('maps volume slider changes to the audio element volume', () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 60, volume: 1 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const volumeSlider = screen.getByTestId('Volume-slider') as HTMLInputElement;
    fireEvent.change(volumeSlider, { target: { value: '35' } });

    expect(audio.volume).toBeCloseTo(0.35);
  });

  it('uses the existing audio time when startTime is zero', async () => {
    renderMediaPlayer({ startTime: 0 });
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 95, currentTime: 5 });

    dispatchAudioEvent(audio, 'loadedmetadata');

    await waitFor(() => {
      expect(screen.getByText('00:05 / 01:35')).toBeInTheDocument();
    });
  });

  it('resets duration and time when the audioSrc prop changes', async () => {
    const initialProps: MediaPlayerProps = {
      audioSrc: '/audio/first.mp3',
      title: 'Track One',
      subtitle: 'Artist'
    };
    const view = render(<MediaPlayer {...initialProps} />);
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 120, currentTime: 45 });
    dispatchAudioEvent(audio, 'loadedmetadata');
    dispatchAudioEvent(audio, 'timeupdate');

    await waitFor(() => {
      expect(screen.getByText('00:45 / 02:00')).toBeInTheDocument();
    });

    view.rerender(
      <MediaPlayer {...initialProps} audioSrc="/audio/second.mp3" title="Second Track" />
    );

    await waitFor(() => {
      expect(screen.getByText('00:00 / 00:00')).toBeInTheDocument();
    });
  });

  it('seeks to the provided startTime once metadata loads', () => {
    renderMediaPlayer({ startTime: 15 });
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 120, currentTime: 0 });

    dispatchAudioEvent(audio, 'loadedmetadata');

    expect(audio.currentTime).toBe(15);
  });

  it('updates the duration label after durationchange events', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 60, currentTime: 0 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    (audio as unknown as { duration: number }).duration = 245;
    dispatchAudioEvent(audio, 'durationchange');

    await waitFor(() => {
      expect(screen.getByText('00:00 / 04:05')).toBeInTheDocument();
    });
  });

  it('syncs the slider value when the audio element fires volumechange', () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 60, volume: 1 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    audio.volume = 0.45;
    dispatchAudioEvent(audio, 'volumechange');

    const volumeSlider = screen.getByTestId('Volume-slider') as HTMLInputElement;
    expect(volumeSlider.value).toBe('45');
  });


  it('compact: hides the volume slider', () => {
    renderMediaPlayer({ variant: 'compact' });
    expect(screen.queryByTestId('Volume-slider')).toBeNull();
  });

  it('compact: does not render the time display', () => {
    renderMediaPlayer({ variant: 'compact' });
    expect(screen.queryByText(/\/\s*\d{2}:\d{2}$/)).toBeNull();
  });

  it('mini: hides the seek slider', () => {
    renderMediaPlayer({ variant: 'mini' });
    expect(screen.queryByTestId('Seek-slider')).toBeNull();
  });

  it('mini: hides the volume slider', () => {
    renderMediaPlayer({ variant: 'mini' });
    expect(screen.queryByTestId('Volume-slider')).toBeNull();
  });

  it('initializes compact MediaControl in playing state when autoPlay is true', () => {
    renderMediaPlayer({ variant: 'compact', autoPlay: true });
    const control = screen.getByRole('button', { name: 'Pause media' });
    expect(control).toHaveAttribute('data-state', 'playing');
  });

  it('initializes default MediaControl in playing state when autoPlay is true', () => {
    renderMediaPlayer({ variant: 'default', autoPlay: true });
    const control = screen.getByRole('button', { name: 'Pause media' });
    expect(control).toHaveAttribute('data-state', 'playing');
  });

  it('swallows errors when initial seek fails during metadata handling', () => {
    renderMediaPlayer({ startTime: 12 });
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 120, currentTime: 0 });

    const originalDescriptor = Object.getOwnPropertyDescriptor(audio, 'currentTime');
    const boundOriginalGet = originalDescriptor?.get?.bind(audio);
    Object.defineProperty(audio, 'currentTime', {
      configurable: true,
      get: boundOriginalGet ?? (() => 0),
      set() {
        throw new Error('seek failure');
      }
    });

    expect(() => dispatchAudioEvent(audio, 'loadedmetadata')).not.toThrow();

    if (originalDescriptor) {
      Object.defineProperty(audio, 'currentTime', originalDescriptor);
    }
  });

  it('swallows errors when seek commits throw', () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 200, currentTime: 0 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const originalDescriptor = Object.getOwnPropertyDescriptor(audio, 'currentTime');
    const boundOriginalGet = originalDescriptor?.get?.bind(audio);
    Object.defineProperty(audio, 'currentTime', {
      configurable: true,
      get: boundOriginalGet ?? (() => 0),
      set() {
        throw new Error('commit failure');
      }
    });

    const seekSlider = screen.getByTestId('Seek-slider') as HTMLInputElement;
    fireEvent.change(seekSlider, { target: { value: '10' } });
    expect(() => fireEvent.mouseUp(seekSlider)).not.toThrow();

    if (originalDescriptor) {
      Object.defineProperty(audio, 'currentTime', originalDescriptor);
    }
  });

  it('falls back to the generic aria label when title is blank', () => {
    renderMediaPlayer({ title: '   ', subtitle: undefined });
    expect(screen.getByRole('region')).toHaveAttribute('aria-label', 'Media player');
  });

  it('replay 10: moves currentTime back by 10s (clamped at 0)', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 120, currentTime: 5 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const replayBtn = screen.getByRole('button', { name: /replay 10 seconds/i });
    await userEvent.click(replayBtn);

    expect(audio.currentTime).toBe(0);
  });

  it('replay 10: moves currentTime back by 10s (normal case)', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 200, currentTime: 50 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const replayBtn = screen.getByRole('button', { name: /replay 10 seconds/i });
    await userEvent.click(replayBtn);

    expect(audio.currentTime).toBe(40);
  });

  it('forward 10: moves currentTime forward by 10s (not beyond duration)', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 55, currentTime: 50 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const fwdBtn = screen.getByRole('button', { name: /forward 10 seconds/i });
    await userEvent.click(fwdBtn);

    expect(audio.currentTime).toBe(55);
  });

  it('forward 10: moves currentTime forward by 10s (normal case)', async () => {
    renderMediaPlayer();
    const audio = document.querySelector('audio') as HTMLAudioElement;
    primeMediaElement(audio, { duration: 200, currentTime: 50 });
    dispatchAudioEvent(audio, 'loadedmetadata');

    const fwdBtn = screen.getByRole('button', { name: /forward 10 seconds/i });
    await userEvent.click(fwdBtn);

    expect(audio.currentTime).toBe(60);
  });

  it('default: renders Close icon button (after volume icon)', () => {
    renderMediaPlayer({ variant: 'default' });
    expect(screen.getByRole('button', { name: /close/i })).toBeInTheDocument();
  });

  it('compact: does not render Close icon button', () => {
    renderMediaPlayer({ variant: 'compact' });
    expect(screen.queryByRole('button', { name: /close/i })).toBeNull();
  });

});
